// worker1.js - Public-facing worker
export default {
  async fetch(request, env) {
    const url = new URL(request.url);
    
    if (url.pathname.startsWith('/api/users')) {
      return env.USERS_SERVICE.fetch(request);
    } else if (url.pathname.startsWith('/api/orders')) {
      return env.ORDERS_SERVICE.fetch(request);
    } else if (url.pathname.startsWith('/api/products')) {
      return env.PRODUCTS_SERVICE.fetch(request);
    }
    
    return new Response('Service not found', { status: 404 });
  }
};

// worker2.js - Users service worker
export default {
  async fetch(request, env) {
    const url = new URL(request.url);
    
    if (url.pathname === '/api/users' && request.method === 'GET') {
      const users = [{ id: 1, name: 'John Doe' }];
      return new Response(JSON.stringify(users), {
        headers: { 'Content-Type': 'application/json' }
      });
    }
    
    return new Response('User service endpoint', { status: 200 });
  }
};

